  // for each element: if it's an array, spread its items into the result
  // otherwise, push the element itself
}

solution:
function flattenOnce<T>(arr: Array<T | T[]>): T[] {
  const result: T[] = [];
  for (const item of arr) {
    if (Array.isArray(item)) {
      result.push(...item);
    } else {
      result.push(item);
    }
  }
  return result;
}

