starterCode:
function debounce<T extends (...args: any[]) => any>(
  func: T,
  delay: number
): ((...args: Parameters<T>) => void) & { cancel: () => void } {
  // keep a timeout id and the latest args/this in closure
  // each call: clear existing timeout, save args/this, schedule a new timeout
  // add a cancel() method on the returned function
}

solution:
function debounce<T extends (...args: any[]) => any>(
  func: T,
  delay: number
): ((...args: Parameters<T>) => void) & { cancel: () => void } {
  let timeoutId: ReturnType<typeof setTimeout> | null = null;
  let lastArgs: Parameters<T>;
  let lastThis: unknown;

  const debounced = function (this: unknown, ...args: Parameters<T>): void {
    lastArgs = args;
    lastThis = this;

    if (timeoutId !== null) {
      clearTimeout(timeoutId);
    }

    timeoutId = setTimeout(() => {
      timeoutId = null;
      func.apply(lastThis, lastArgs);
    }, delay);
  } as ((...args: Parameters<T>) => void) & { cancel: () => void };

  debounced.cancel = () => {
    if (timeoutId !== null) {
      clearTimeout(timeoutId);
      timeoutId = null;
    }
  };

  return debounced;
}

starterCode:
function deepClone<T>(obj: T): T {
  // use a WeakMap<object, any> to remember objects already cloned (handles circularity)
  // dispatch on type: primitive/null -> return as-is; Date/RegExp -> special constructors;
  // Map/Set -> clone entries; Array -> clone items; plain object -> clone own enumerable keys
}

solution:
function deepClone<T>(obj: T): T {
  const seen = new WeakMap<object, unknown>();

  function clone(value: unknown): unknown {
    if (value === null || typeof value !== 'object') {
      return value;
    }

    if (typeof value === 'function') {
      return value;
    }

    if (seen.has(value as object)) {
      return seen.get(value as object);
    }

    if (value instanceof Date) {
      return new Date(value.getTime());
    }

    if (value instanceof RegExp) {
      return new RegExp(value.source, value.flags);
    }

    if (value instanceof Map) {
      const clonedMap = new Map();
      seen.set(value, clonedMap);
      value.forEach((v, k) => clonedMap.set(clone(k), clone(v)));
      return clonedMap;
    }

    if (value instanceof Set) {
      const clonedSet = new Set();
      seen.set(value, clonedSet);
      value.forEach(v => clonedSet.add(clone(v)));
      return clonedSet;
    }

    if (Array.isArray(value)) {
      const clonedArr: unknown[] = [];
      seen.set(value, clonedArr);
      value.forEach((item, i) => { clonedArr[i] = clone(item); });
      return clonedArr;
    }

    const clonedObj = Object.create(Object.getPrototypeOf(value));
    seen.set(value, clonedObj);
    for (const key of Object.keys(value as object)) {
      clonedObj[key] = clone((value as Record<string, unknown>)[key]);
    }
    return clonedObj;
  }

  return clone(obj) as T;
}

starterCode:
function curry<T extends (...args: any[]) => any>(
  func: T,
  arity: number = func.length
): (...args: any[]) => any {
  // return a function that collects args; if collected.length >= arity, call func
  // otherwise return a new function that continues collecting (concat old + new args)
}

solution:
function curry<T extends (...args: any[]) => any>(
  func: T,
  arity: number = func.length
): (...args: any[]) => any {
  return function curried(this: unknown, ...args: any[]): any {
    if (args.length >= arity) {
      return func.apply(this, args);
    }
    return (...nextArgs: any[]) => curried.apply(this, args.concat(nextArgs));
  };
}

