type Listener = (...args: any[]) => void;

class EventEmitter {
  private listeners: Map<string, Listener[]> = new Map();

  on(event: string, listener: Listener): void {
    // append listener to the array for this event (create the array if missing)
  }

  off(event: string, listener: Listener): void {
    // remove only this specific listener reference from the event's array
  }

  emit(event: string, ...args: any[]): void {
    // call each listener currently registered for this event, in order
    // iterate over a COPY of the array, not the live one
  }

  once(event: string, listener: Listener): void {
    // wrap listener so it calls off() on itself right after firing once
  }
