solution:
type Listener = (...args: any[]) => void;

class EventEmitter {
  private listeners: Map<string, Listener[]> = new Map();

  on(event: string, listener: Listener): void {
    const existing = this.listeners.get(event);
    if (existing) {
      existing.push(listener);
    } else {
      this.listeners.set(event, [listener]);
    }
  }

  off(event: string, listener: Listener): void {
    const existing = this.listeners.get(event);
    if (!existing) return;
    const index = existing.indexOf(listener);
    if (index !== -1) {
      existing.splice(index, 1);
    }
  }

  emit(event: string, ...args: any[]): void {
    const existing = this.listeners.get(event);
    if (!existing) return;
    for (const listener of [...existing]) {
      listener(...args);
    }
  }

  once(event: string, listener: Listener): void {
    const wrapper: Listener = (...args: any[]) => {
      this.off(event, wrapper);
      listener(...args);
    };
    this.on(event, wrapper);
  }
}

starterCode:
function promiseAll<T>(promises: Array<T | Promise<T>>): Promise<T[]> {
  return new Promise((resolve, reject) => {
    // handle the empty array case immediately
    // track results in a pre-sized array (to preserve order) and a completed counter
    // Promise.resolve(item).then(...) normalizes plain values into promises
    // resolve once completed === promises.length; reject immediately on any failure
  });
}

solution:
function promiseAll<T>(promises: Array<T | Promise<T>>): Promise<T[]> {
  return new Promise((resolve, reject) => {
    if (promises.length === 0) {
      resolve([]);
      return;
    }

    const results: T[] = new Array(promises.length);
    let completed = 0;

    promises.forEach((item, index) => {
      Promise.resolve(item).then(
        value => {
          results[index] = value;
          completed++;
          if (completed === promises.length) {
            resolve(results);
          }
        },
        reason => reject(reason)
      );
    });
  });
}

starterCode:
function deepEqual(a: unknown, b: unknown): boolean {
  // 1. handle NaN special case and primitive/reference equality via Object.is or ===
  // 2. if either isn't an object (or is null), they're only equal if step 1 already matched
  // 3. compare Array.isArray(a) === Array.isArray(b) (arrays vs plain objects are never equal)
  // 4. compare key counts, then recursively compare each value
}

solution:
function deepEqual(a: unknown, b: unknown): boolean {
  if (Object.is(a, b)) {
    return true;
  }

  if (typeof a !== 'object' || typeof b !== 'object' || a === null || b === null) {
    return false;
  }

  if (Array.isArray(a) !== Array.isArray(b)) {
    return false;
  }

  const keysA = Object.keys(a as object);
  const keysB = Object.keys(b as object);

  if (keysA.length !== keysB.length) {
    return false;
  }

  return keysA.every(key =>
    Object.prototype.hasOwnProperty.call(b, key) &&
    deepEqual((a as Record<string, unknown>)[key], (b as Record<string, unknown>)[key])
  );
}

