solution:
function chunk<T>(arr: T[], size: number): T[][] {
  if (size <= 0) {
    throw new Error('size must be greater than 0');
  }

  const result: T[][] = [];
  for (let i = 0; i < arr.length; i += size) {
    result.push(arr.slice(i, i + size));
  }
  return result;
}

