solution:
interface Observer<T> {
  next?: (value: T) => void;
  error?: (error: Error) => void;
  complete?: () => void;
}
interface Subscription {
  unsubscribe(): void;
}

class Observable<T> {
  constructor(private subscribeFn: (observer: Required<Observer<T>>) => () => void) {}

  subscribe(observer: Partial<Observer<T>>): Subscription {
    let closed = false;

    const safeObserver: Required<Observer<T>> = {
      next: value => { if (!closed) observer.next?.(value); },
      error: error => { if (!closed) { closed = true; observer.error?.(error); } },
      complete: () => { if (!closed) { closed = true; observer.complete?.(); } }
    };

    const cleanup = this.subscribeFn(safeObserver);

    return {
      unsubscribe: () => {
        if (!closed) {
          closed = true;
          cleanup();
        }
      }
    };
  }

  map<U>(fn: (value: T) => U): Observable<U> {
    return new Observable<U>(observer => {
      const sub = this.subscribe({
        next: value => {
          try {
            observer.next(fn(value));
          } catch (err) {
            observer.error(err instanceof Error ? err : new Error(String(err)));
          }
        },
        error: err => observer.error(err),
        complete: () => observer.complete()
      });
      return () => sub.unsubscribe();
    });
  }

  filter(predicate: (value: T) => boolean): Observable<T> {
    return new Observable<T>(observer => {
      const sub = this.subscribe({
        next: value => {
          try {
            if (predicate(value)) observer.next(value);
          } catch (err) {
            observer.error(err instanceof Error ? err : new Error(String(err)));
          }
        },
        error: err => observer.error(err),
        complete: () => observer.complete()
      });
      return () => sub.unsubscribe();
    });
  }

  take(count: number): Observable<T> {
    return new Observable<T>(observer => {
      if (count <= 0) {
        observer.complete();
        return () => {};
      }
      let taken = 0;
      const sub = this.subscribe({
        next: value => {
          observer.next(value);
          taken++;
          if (taken >= count) {
            observer.complete();
            sub.unsubscribe();
          }
        },
        error: err => observer.error(err),
        complete: () => observer.complete()
      });
      return () => sub.unsubscribe();
    });
  }

  catchError(handler: (error: Error) => Observable<T>): Observable<T> {
    return new Observable<T>(observer => {
      let innerSub: Subscription | null = null;
      const sub = this.subscribe({
        next: value => observer.next(value),
        error: err => {
          innerSub = handler(err).subscribe(observer);
        },
        complete: () => observer.complete()
      });
      return () => {
        sub.unsubscribe();
        innerSub?.unsubscribe();
      };
    });
  }
}

