type Executor<T> = (
  resolve: (value: T | PromiseLike<T>) => void,
  reject: (reason?: unknown) => void
) => void;

type FulfilledHandler<T, U> = (value: T) => U | PromiseLike<U>;
type RejectedHandler<U> = (reason: unknown) => U | PromiseLike<U>;

class MyPromise<T> {
  private state: 'pending' | 'fulfilled' | 'rejected' = 'pending';
  private value: T | undefined;
  private reason: unknown;
  private onFulfilledCallbacks: Array<() => void> = [];
  private onRejectedCallbacks: Array<() => void> = [];

  constructor(executor: Executor<T>) {
    // call executor with resolve/reject that:
    //  - if value is thenable, chain via its .then instead of settling directly
    //  - otherwise settle state/value once, then flush queued callbacks
  }

  then<U = T>(onFulfilled?: FulfilledHandler<T, U>, onRejected?: RejectedHandler<U>): MyPromise<U> {
    // return a new MyPromise; schedule handler execution with setTimeout(...,0) for async semantics
    // if this promise is already settled, still schedule asynchronously
    // if pending, push a callback that will run once settled
  }
}

solution:
type Executor<T> = (
  resolve: (value: T | PromiseLike<T>) => void,
  reject: (reason?: unknown) => void
) => void;

type FulfilledHandler<T, U> = (value: T) => U | PromiseLike<U>;
type RejectedHandler<U> = (reason: unknown) => U | PromiseLike<U>;

function isThenable(value: unknown): value is PromiseLike<unknown> {
  return (
    (typeof value === 'object' || typeof value === 'function') &&
    value !== null &&
    typeof (value as { then?: unknown }).then === 'function'
  );
}

class MyPromise<T> {
  private state: 'pending' | 'fulfilled' | 'rejected' = 'pending';
  private value: T | undefined;
  private reason: unknown;
  private onFulfilledCallbacks: Array<() => void> = [];
  private onRejectedCallbacks: Array<() => void> = [];

  constructor(executor: Executor<T>) {
    const resolve = (value: T | PromiseLike<T>): void => {
      if (this.state !== 'pending') return;

      if (isThenable(value)) {
        value.then(resolve as (v: unknown) => void, reject);
        return;
      }

      this.state = 'fulfilled';
      this.value = value;
      this.onFulfilledCallbacks.forEach(cb => cb());
    };

    const reject = (reason?: unknown): void => {
      if (this.state !== 'pending') return;
      this.state = 'rejected';
      this.reason = reason;
      this.onRejectedCallbacks.forEach(cb => cb());
    };

    try {
      executor(resolve, reject);
    } catch (error) {
      reject(error);
    }
  }

  then<U = T>(onFulfilled?: FulfilledHandler<T, U>, onRejected?: RejectedHandler<U>): MyPromise<U> {
    return new MyPromise<U>((resolve, reject) => {
      const handleFulfilled = () => {
        setTimeout(() => {
          try {
            if (onFulfilled) {
              resolve(onFulfilled(this.value as T));
            } else {
              resolve(this.value as unknown as U);
            }
          } catch (error) {
            reject(error);
          }
        }, 0);
      };

      const handleRejected = () => {
        setTimeout(() => {
          try {
            if (onRejected) {
              resolve(onRejected(this.reason));
            } else {
              reject(this.reason);
            }
          } catch (error) {
            reject(error);
          }
        }, 0);
      };

      if (this.state === 'fulfilled') {
        handleFulfilled();
      } else if (this.state === 'rejected') {
        handleRejected();
      } else {
        this.onFulfilledCallbacks.push(handleFulfilled);
        this.onRejectedCallbacks.push(handleRejected);
      }
    });
  }
}

description.en:
Implement an `AsyncMutex` class that guarantees only one async operation at a time can run inside a critical section, even when multiple callers try to acquire it concurrently. Unlike a concurrency-limited queue (which schedules independent tasks), a mutex protects a single shared resource from simultaneous access.

**Requirements:**
- `acquire()` returns a promise that resolves with a `release` function once the lock is available
- If the lock is already held, `acquire()` callers queue up and are granted the lock strictly in FIFO order as it's released
- `release()` must be idempotent — calling it more than once for the same acquisition has no additional effect
- Provide a `runExclusive(fn)` convenience method that acquires, runs `fn`, and always releases (even if `fn` throws or its returned promise rejects)

**Class signature:**
```typescript
class AsyncMutex {
  acquire(): Promise<() => void>;
  runExclusive<T>(fn: () => Promise<T> | T): Promise<T>;
}
```

**Example:**
```typescript
const mutex = new AsyncMutex();
const log: string[] = [];

async function task(name: string) {
  const release = await mutex.acquire();
  log.push(`${name}:start`);
  await delay(50);
  log.push(`${name}:end`);
  release();
}

await Promise.all([task('A'), task('B')]);
// log === ['A:start', 'A:end', 'B:start', 'B:end'] -- never interleaved
```

**Edge cases:**
- Many concurrent `acquire()` calls must still execute the critical section strictly one at a time, in call order
- `runExclusive` must release the lock even when the passed function throws synchronously or its promise rejects
- Calling `release()` twice must not let a second, unrelated waiter acquire the lock early
- An empty mutex (`acquire()` called when nothing else holds the lock) resolves immediately, without an artificial delay

