  private locked = false;
  private waiters: Array<() => void> = [];

  acquire(): Promise<() => void> {
    // if not locked: lock immediately and resolve with a release function
    // if locked: queue a resolver in `waiters`, to be called when release() runs
    // the release function must be idempotent and hand the lock to the next waiter (or unlock)
  }

  async runExclusive<T>(fn: () => Promise<T> | T): Promise<T> {
    // acquire, run fn in try/finally, always release
  }
}

solution:
class AsyncMutex {
  private locked = false;
  private waiters: Array<() => void> = [];

  acquire(): Promise<() => void> {
    return new Promise(resolve => {
      const grant = () => {
        this.locked = true;
        let released = false;
        resolve(() => {
          if (released) return;
          released = true;
          this.releaseLock();
        });
      };

      if (!this.locked) {
        grant();
      } else {
        this.waiters.push(grant);
      }
    });
  }

  private releaseLock(): void {
    const next = this.waiters.shift();
    if (next) {
      next();
    } else {
      this.locked = false;
    }
  }

  async runExclusive<T>(fn: () => Promise<T> | T): Promise<T> {
    const release = await this.acquire();
    try {
      return await fn();
    } finally {
      release();
    }
  }
}

