interface TaskDef<T> {
  deps: string[];
  run: () => Promise<T>;
}

function runTasks<T>(tasks: Record<string, TaskDef<T>>): Promise<Record<string, T>> {
  // 1. validate: every dep name exists in `tasks`
  // 2. detect cycles (e.g. DFS with a 'visiting' set)
  // 3. schedule: for each task, build a promise that awaits Promise.all(deps' promises) then runs it
  //    build these promises for ALL tasks up front so independent ones start immediately and concurrently
  // 4. Promise.all everything, collect results by name
}

solution:
interface TaskDef<T> {
  deps: string[];
  run: () => Promise<T>;
}

function detectCycle(tasks: Record<string, TaskDef<unknown>>): string | null {
  const state = new Map<string, 'visiting' | 'done'>();

  function visit(name: string, path: string[]): string | null {
    const status = state.get(name);
    if (status === 'done') return null;
    if (status === 'visiting') return [...path, name].join(' -> ');

    state.set(name, 'visiting');
    for (const dep of tasks[name]?.deps ?? []) {
      const cyclePath = visit(dep, [...path, name]);
      if (cyclePath) return cyclePath;
    }
    state.set(name, 'done');
    return null;
  }

  for (const name of Object.keys(tasks)) {
    const cyclePath = visit(name, []);
    if (cyclePath) return cyclePath;
  }
  return null;
}

function runTasks<T>(tasks: Record<string, TaskDef<T>>): Promise<Record<string, T>> {
  for (const [name, def] of Object.entries(tasks)) {
    for (const dep of def.deps) {
      if (!(dep in tasks)) {
        return Promise.reject(new Error(`Task "${name}" depends on unknown task "${dep}"`));
      }
    }
  }

  const cyclePath = detectCycle(tasks);
  if (cyclePath) {
    return Promise.reject(new Error(`Circular dependency detected: ${cyclePath}`));
  }

  const promises: Record<string, Promise<T>> = {};

  for (const name of Object.keys(tasks)) {
    promises[name] = (async () => {
      const def = tasks[name];
      await Promise.all(def.deps.map(dep => promises[dep]));
      return def.run();
    })();
  }

  return Promise.all(
    Object.entries(promises).map(async ([name, p]) => [name, await p] as const)
  ).then(entries => Object.fromEntries(entries));
}

