  // (used as the recency tiebreaker among keys sharing the same frequency)
  private freqGroups = new Map<number, Map<K, true>>();
  private minFreq = 0;

  constructor(capacity: number) {
    this.capacity = capacity;
  }

  get(key: K): V | undefined {
    // if present: bump frequency, return value; else undefined
  }

  put(key: K, value: V): void {
    // if capacity is 0: no-op
    // if key exists: update value, bump frequency
    // else: evict from freqGroups.get(minFreq) if at capacity, then insert at frequency 1, minFreq = 1
  }

  private bumpFrequency(key: K): void {
    // remove key from its current frequency group, add to (freq+1) group
    // if that emptied the group that WAS minFreq, increment minFreq
