  getState(): S;
  dispatch(action: A): void;
  subscribe(listener: () => void): () => void;
}

function createStore<S, A>(reducer: Reducer<S, A>, initialState: S): Store<S, A> {
  // keep state in a closure variable; listeners in an array
  // dispatch: state = reducer(state, action); notify a COPY of the listeners array
  // subscribe: push listener, return an idempotent unsubscribe that removes it once
}

solution:
type Reducer<S, A> = (state: S, action: A) => S;
interface Store<S, A> {
  getState(): S;
  dispatch(action: A): void;
  subscribe(listener: () => void): () => void;
}

function createStore<S, A>(reducer: Reducer<S, A>, initialState: S): Store<S, A> {
  let state = initialState;
  let listeners: Array<() => void> = [];

  function getState(): S {
    return state;
  }

  function dispatch(action: A): void {
    state = reducer(state, action);
    for (const listener of [...listeners]) {
      listener();
    }
  }

  function subscribe(listener: () => void): () => void {
    listeners.push(listener);
    let unsubscribed = false;
    return () => {
      if (unsubscribed) return;
      unsubscribed = true;
      listeners = listeners.filter(l => l !== listener);
    };
  }

  return { getState, dispatch, subscribe };
}

description.en:
Implement `processInBatches`, which consumes an `AsyncIterable` source, groups items into batches of a given size, and processes each batch with a concurrency-limited async handler — without ever pulling more items from the source than the current batch needs (backpressure: the source is only advanced as fast as processing can keep up).

**Requirements:**
- Pull items from the async iterable one at a time; group them into arrays of `batchSize` (the final batch may be smaller)
- Call `processBatch(batch)` for each full or final batch and `await` it before pulling further items for the *next* batch (this is the backpressure: don't buffer the whole source in memory or race ahead of processing)
- Collect and return the results of every `processBatch` call, in order, once the source is exhausted
- If `processBatch` rejects, stop pulling from the source and propagate that rejection

**Function signature:**
```typescript
async function processInBatches<T, R>(
  source: AsyncIterable<T>,
  batchSize: number,
  processBatch: (batch: T[]) => Promise<R>
): Promise<R[]>
```

**Example:**
```typescript
async function* source() {
  for (let i = 1; i <= 5; i++) { yield i; }
}

const results = await processInBatches(source(), 2, async batch => {
  return batch.reduce((a, b) => a + b, 0);
});
// batches: [1,2], [3,4], [5] -> results: [3, 7, 5]
```

**Edge cases:**
- Source producing zero items → resolves with `[]`, `processBatch` never called
- Source length not evenly divisible by `batchSize` → final smaller batch is still processed
- `processBatch` for an early batch takes longer than pulling the next batch's items would — the implementation must not pull ahead regardless, honoring backpressure
- The source is an async generator that lazily produces items (e.g. from paginated network calls) — items after a rejected batch should never be requested

description.ru:
Реализуйте `processInBatches`, которая потребляет источник `AsyncIterable`, группирует элементы в батчи заданного размера и обрабатывает каждый батч асинхронным обработчиком с ограничением параллелизма — никогда не вытягивая из источника больше элементов, чем нужно текущему батчу (бэкпрешер: источник продвигается ровно с той скоростью, с какой успевает обработка).

**Требования:**
- Вытягивайте элементы из async-итерируемого источника по одному; группируйте их в массивы по `batchSize` (последний батч может быть меньше)
- Вызывайте `processBatch(batch)` для каждого полного или финального батча и `await`-те его перед вытягиванием элементов для *следующего* батча (это и есть бэкпрешер: не буферизировать весь источник в памяти и не забегать вперёд обработки)
- Соберите и верните результаты всех вызовов `processBatch`, по порядку, когда источник исчерпан
- Если `processBatch` реджектится, прекратите вытягивать из источника и пробросьте этот реджект

**Сигнатура функции:**
```typescript
async function processInBatches<T, R>(
  source: AsyncIterable<T>,
  batchSize: number,
  processBatch: (batch: T[]) => Promise<R>
): Promise<R[]>
```

**Пример:**
```typescript
async function* source() {
  for (let i = 1; i <= 5; i++) { yield i; }
}

const results = await processInBatches(source(), 2, async batch => {
  return batch.reduce((a, b) => a + b, 0);
});
// батчи: [1,2], [3,4], [5] -> results: [3, 7, 5]
```

**Граничные случаи:**
- Источник, не производящий элементов → резолвится в `[]`, `processBatch` ни разу не вызван
- Длина источника не кратна `batchSize` → финальный меньший батч всё равно обрабатывается
- `processBatch` для раннего батча занимает больше времени, чем заняло бы вытягивание элементов следующего батча — реализация всё равно не должна забегать вперёд, соблюдая бэкпрешер
- Источник — асинхронный генератор, лениво производящий элементы (например, из постраничных сетевых вызовов) — элементы после отклонённого батча никогда не должны запрашиваться

