async function processInBatches<T, R>(
  source: AsyncIterable<T>,
  batchSize: number,
  processBatch: (batch: T[]) => Promise<R>
): Promise<R[]> {
  // manually drive source[Symbol.asyncIterator]() so you control exactly when the next item is pulled
  // accumulate items into `currentBatch`; when it reaches batchSize, await processBatch(...) before continuing
  // after the loop ends, process any leftover partial batch
}

solution:
async function processInBatches<T, R>(
  source: AsyncIterable<T>,
  batchSize: number,
  processBatch: (batch: T[]) => Promise<R>
): Promise<R[]> {
  const results: R[] = [];
  let currentBatch: T[] = [];
  const iterator = source[Symbol.asyncIterator]();

  while (true) {
    const { value, done } = await iterator.next();
    if (done) break;

    currentBatch.push(value);

    if (currentBatch.length >= batchSize) {
      results.push(await processBatch(currentBatch));
      currentBatch = [];
    }
  }

  if (currentBatch.length > 0) {
    results.push(await processBatch(currentBatch));
  }

  return results;
}

