function setIn<T extends object>(obj: T, path: Array<string | number>, value: unknown): T {
  // base case: empty path -> return value directly (document this choice)
  // otherwise: shallow-copy obj (Array.isArray ? [...obj] : {...obj})
  //            recursively setIn(copy[path[0]] ?? {}, path.slice(1), value) and assign it back onto the copy
}

solution:
function setIn<T extends object>(obj: T, path: Array<string | number>, value: unknown): T {
  if (path.length === 0) {
    return value as T;
  }

  const [key, ...rest] = path;
  const copy: any = Array.isArray(obj) ? [...obj] : { ...obj };

  const existingChild = (obj as any)[key];
  const childBase = existingChild !== undefined && typeof existingChild === 'object'
    ? existingChild
    : (typeof rest[0] === 'number' ? [] : {});

  copy[key] = setIn(childBase, rest, value);

  return copy as T;
}
